const checkpointNode = $input.first().json?.CheckpointLoaderSimple;
const availableCheckpoints = Array.isArray(checkpointNode?.input?.required?.ckpt_name?.[0])
  ? checkpointNode.input.required.ckpt_name[0]
  : [];
const request = $('Webhook').first().json?.body ?? $('Webhook').first().json ?? {};
const promptText = typeof request.prompt === 'string' && request.prompt.trim()
  ? request.prompt.trim()
  : 'a studio product photo of a red apple on a table';
const negativePrompt = typeof request.negative_prompt === 'string' && request.negative_prompt.trim()
  ? request.negative_prompt.trim()
  : 'blurry, low quality, distorted';
const requestedCheckpoint = typeof request.checkpoint === 'string' && request.checkpoint.trim()
  ? request.checkpoint.trim()
  : (availableCheckpoints.find((name) => /sd.?1\.5|v1-5/i.test(name)) ?? 'v1-5-pruned-emaonly.safetensors');
const seed = Number.isFinite(Number(request.seed)) ? Number(request.seed) : 1;
const steps = Number.isFinite(Number(request.steps)) ? Number(request.steps) : 12;
const cfg = Number.isFinite(Number(request.cfg)) ? Number(request.cfg) : 7;
const width = Number.isFinite(Number(request.width)) ? Number(request.width) : 512;
const height = Number.isFinite(Number(request.height)) ? Number(request.height) : 512;
const samplerName = typeof request.sampler_name === 'string' && request.sampler_name.trim()
  ? request.sampler_name.trim()
  : 'euler';
const scheduler = typeof request.scheduler === 'string' && request.scheduler.trim()
  ? request.scheduler.trim()
  : 'normal';
const clientId = typeof request.client_id === 'string' && request.client_id.trim()
  ? request.client_id.trim()
  : 'prototype-local-sd15';
const comfyuiBaseUrl = typeof request.comfyuiBaseUrl === 'string' && request.comfyuiBaseUrl.trim()
  ? request.comfyuiBaseUrl.trim().replace(/\/$/, '')
  : 'http://comfyui:8188';

return [{
  json: {
    comfyui_base_url: comfyuiBaseUrl,
    requestedCheckpoint,
    availableCheckpoints,
    checkpointCount: availableCheckpoints.length,
    prompt: promptText,
    negativePrompt,
    width,
    height,
    steps,
    cfg,
    samplerName,
    scheduler,
    clientId,
    comfyPayload: {
      client_id: clientId,
      prompt: {
        '3': {
          class_type: 'CheckpointLoaderSimple',
          inputs: {
            ckpt_name: requestedCheckpoint
          }
        },
        '4': {
          class_type: 'CLIPTextEncode',
          inputs: {
            text: promptText,
            clip: ['3', 1]
          }
        },
        '5': {
          class_type: 'CLIPTextEncode',
          inputs: {
            text: negativePrompt,
            clip: ['3', 1]
          }
        },
        '6': {
          class_type: 'EmptyLatentImage',
          inputs: {
            width,
            height,
            batch_size: 1
          }
        },
        '7': {
          class_type: 'KSampler',
          inputs: {
            model: ['3', 0],
            seed,
            steps,
            cfg,
            sampler_name: samplerName,
            scheduler,
            positive: ['4', 0],
            negative: ['5', 0],
            latent_image: ['6', 0],
            denoise: 1
          }
        },
        '8': {
          class_type: 'VAEDecode',
          inputs: {
            samples: ['7', 0],
            vae: ['3', 2]
          }
        },
        '9': {
          class_type: 'SaveImage',
          inputs: {
            images: ['8', 0],
            filename_prefix: 'prototype_sd15'
          }
        }
      }
    }
  }
}];

const request = $('Prepare SD15 Prompt').first().json;
const response = $input.first().json;
const body = response.body ?? {};
const nodeErrors = body?.node_errors?.['3']?.errors ?? [];
const errorDetails = nodeErrors.length > 0 ? nodeErrors : (body?.error?.details ?? null);

return [{
  json: {
    queued: response.statusCode >= 200 && response.statusCode < 300,
    queueAttempted: true,
    statusCode: response.statusCode ?? null,
    promptId: body?.prompt_id ?? null,
    queueNumber: body?.number ?? null,
    comfyuiBaseUrl: request.comfyui_base_url,
    requestedCheckpoint: request.requestedCheckpoint,
    availableCheckpoints: request.availableCheckpoints,
    checkpointCount: request.checkpointCount,
    prompt: request.prompt,
    negativePrompt: request.negativePrompt,
    width: request.width,
    height: request.height,
    steps: request.steps,
    cfg: request.cfg,
    samplerName: request.samplerName,
    scheduler: request.scheduler,
    errorType: response.statusCode >= 200 && response.statusCode < 300 ? null : (body?.error?.type ?? 'queue_error'),
    errorMessage: response.statusCode >= 200 && response.statusCode < 300 ? null : (body?.error?.message ?? response.statusMessage ?? 'Queue request failed'),
    errorDetails,
    rawResponse: body,
    comfyPayload: request.comfyPayload
  }
}];
